import{_ as a,o as n,c as i,j as e,a as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"4. Alfred Health General Conditions","description":"","frontmatter":{"title":"4. Alfred Health General Conditions","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["schedules","hospital-specific"]},"headers":[],"relativePath":"ebas/mspp/schedules/4-alfred-health-general-conditions.md","filePath":"ebas/mspp/schedules/4-alfred-health-general-conditions.md"}'),l={name:"ebas/mspp/schedules/4-alfred-health-general-conditions.md"};function s(r,t,h,d,c,p){return n(),i("div",null,[...t[0]||(t[0]=[e("h1",{id:"_4-alfred-health-general-conditions",tabindex:"-1"},[o("4. Alfred Health General Conditions "),e("a",{class:"header-anchor",href:"#_4-alfred-health-general-conditions","aria-label":'Permalink to "4. Alfred Health General Conditions"'},"​")],-1),e("p",null,"Formatting note",-1),e("p",null,"The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.",-1),e("p",null,"```text 1. Incidence This schedule shall only apply to persons employed by Alfred Health and eligible to be members of the Union. 2. Definitions “Parties” means the Health Services Union and Alfred Health 3. Merit Criteria – Medical Scientists The Medical Scientists Classification Review Committee (MSCRC) will process applications for reclassification based on the merit criteria as provided for by the Agreement. The make-up of the MSCRC shall comprise equal numbers of employee representatives, which may include the Union, and employer representatives. The Committee will receive and adjudicate on applications twice per year in June and December. 4. Overtime 4.1 Notwithstanding any other provision of the Agreement, a Scientist employed at Alfred Health may elect in lieu of payment of overtime to take time off equivalent to the time worked at the appropriate penalty rate at a time mutually agreed between the employer and the employee, in which case the time off shall be granted within two weeks of working the overtime, or by mutual agreement between the employer and the employee, a Scientist may elect in lieu of payment of overtime to take time off equivalent to the time worked at ordinary time in conjunction with their annual leave. 4.2 In the event that a Scientist elects in lieu of payment of overtime to take time off in conjunction with their annual leave, such time will not be subject to the annual leave loading. 5. Roster Changes 5.1 Where a dispute arises between an employee and the manager of a unit or department in any attempt to alter the current rostering arrangements, the status quo will remain until an alternative arrangement is agreed or resolved by referral of the matter to the Alfred Health (Medical Scientists/Psychologists) Joint Consultative Committee. Any dispute arising from this clause shall be dealt with as per the Disputes Settling Procedures of the Agreement. 5.2 Notwithstanding the provisions of clause 57 of the Agreement, the period of notice for roster changes at Alfred Health shall be 14 days. 6. Enhanced Leave Flexibility Annual Leave or Long Service Leave may be taken in association with short-term conference, scientific exchange or visitation leave.",-1),e("ol",null,[e("li",null,[e("p",null,"Personal Leave Clause 7(a) shall apply in lieu of 64.3e of the Agreement. (a) An employee may be absent through sickness or requirement to attend a health professional without furnishing evidence of such for a total of 24 hours, with a minimum period of 2 hours, in any one year of service. (b) The employer shall not terminate the service of any employee during the currency of any period of personal leave.")]),e("li",null,[e("p",null,"Occupational Health and Safety 8.1 The provisions of this subclause shall be read and interpreted subject to the Occupational Health and Safety Act 2004 (VIC). 8.2 The employer will maintain a system of agreed designated work groups with employees and their representatives which may include the Union. Elections for employee occupational health and safety representatives shall be conducted by the parties to this schedule. There shall be two health and safety representatives from the Alfred Hospital campus nominated to the Alfred Hospital Occupational Health and Safety Committee to represent areas in which employees covered by the schedule are employed. One shall represent the pathology departments. while the other will represent non-pathology departments. These representatives shall be nominated by employees from all the health and safety representatives selected from the Designated Work Groups who are covered by this schedule at the Alfred Hospital campus. 8.3 With respect to Caulfield Campus Occupational Health and Safety Committee, one health and safety representative shall be nominated by employees from the Designated Work Groups covered by this schedule at the Caulfield campus. 8.4 Occupational health and safety representatives shall be entitled to attend Alfred Health- approved, accredited courses on paid leave. Any reasonable course fees shall be paid by the employer. ```")])],-1)])])}const u=a(l,[["render",s]]);export{f as __pageData,u as default};
